#!/bin/bash
# Spyre vLLM Benchmark Runner
#
# Reads JSON test configs (generated by generate_test_configs.py) and runs
# vLLM benchmarks. Supports parallel execution across multiple models when
# multiple Spyre PF cards are available.
#
# Parallelism: When PARALLEL=true (default), tests for different models run
# concurrently. Tests for the same model still run sequentially.

set -eo pipefail

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
REPO_ROOT="$(dirname "$SCRIPT_DIR")"
RESULTS_DIR="${RESULTS_DIR:-$REPO_ROOT/results}"
CONFIG_FILE="${CONFIG_FILE:-$REPO_ROOT/config/benchmark_config.yaml}"
TIMESTAMP=$(date -u +"%Y%m%dT%H%M%SZ")
PARALLEL="${PARALLEL:-true}"

mkdir -p "$RESULTS_DIR"

# -----------------------------------------------
# Detect benchmark CLI
# -----------------------------------------------
detect_bench_command() {
    if vllm bench --help &>/dev/null; then
        BENCH_CMD="vllm bench"
    elif python3 -m vllm.entrypoints.cli.main bench --help &>/dev/null; then
        BENCH_CMD="python3 -m vllm.entrypoints.cli.main bench"
    else
        BENCH_CMD=""
    fi
    echo "  Bench CLI: ${BENCH_CMD:-LEGACY FALLBACK}"
}

# -----------------------------------------------
# json2args: convert JSON params to CLI args
# -----------------------------------------------
json2args() {
    local json_string=$1
    echo "$json_string" | jq -r '
        to_entries |
        map(
            if .value == true then "--" + (.key | gsub("_"; "-"))
            elif .value == false then ""
            else "--" + (.key | gsub("_"; "-")) + " " + (.value | tostring)
            end
        ) |
        map(select(. != "")) |
        join(" ")
    '
}

# -----------------------------------------------
# Run a single benchmark test
# -----------------------------------------------
run_single_test() {
    local test_type=$1
    local test_name=$2
    local bench_args=$3

    echo ""
    echo "┌─ [$test_type] $test_name"

    local bench_command
    if [[ -n "$BENCH_CMD" ]]; then
        bench_command="$BENCH_CMD $test_type --output-json $RESULTS_DIR/${test_name}.json $bench_args"
    else
        if [[ "$test_type" == "latency" ]]; then
            bench_command="python3 -m vllm.benchmarks.latency --output-json $RESULTS_DIR/${test_name}.json $bench_args"
        elif [[ "$test_type" == "throughput" ]]; then
            bench_command="python3 -m vllm.benchmarks.throughput --output-json $RESULTS_DIR/${test_name}.json $bench_args"
        fi
    fi

    echo "│ Command: $bench_command"
    echo "│"

    # Save command for reproducibility
    jq -n \
        --arg command "$bench_command" \
        --arg device "spyre" \
        --arg timestamp "$TIMESTAMP" \
        '{command: $command, device: $device, timestamp: $timestamp}' \
        > "$RESULTS_DIR/${test_name}.commands"

    if eval "$bench_command" 2>&1; then
        # Print key results inline
        if [[ -f "$RESULTS_DIR/${test_name}.json" ]]; then
            echo "│"
            if [[ "$test_type" == "latency" ]]; then
                echo "│ Result: $(jq -r '"avg=\(.avg_latency | tostring | .[0:6])s  p50=\(.percentiles."50" | tostring | .[0:6])s  p99=\(.percentiles."99" | tostring | .[0:6])s"' "$RESULTS_DIR/${test_name}.json" 2>/dev/null || echo "see JSON")"
            elif [[ "$test_type" == "throughput" ]]; then
                echo "│ Result: $(jq -r '"\(.tokens_per_second | tostring | .[0:7]) tok/s  \(.requests_per_second | tostring | .[0:5]) req/s  \(.elapsed_time | tostring | .[0:6])s elapsed"' "$RESULTS_DIR/${test_name}.json" 2>/dev/null || echo "see JSON")"
            fi
        fi
        echo "└─ PASS"
        return 0
    else
        echo "└─ FAIL (exit code: $?)"
        return 1
    fi
}

# -----------------------------------------------
# Run all tests for a specific model (sequential)
# -----------------------------------------------
run_model_tests() {
    local model_filter=$1
    local test_file=$2
    local test_type=$3
    local pass_count=0
    local fail_count=0
    local total=0

    while read -r params; do
        test_name=$(echo "$params" | jq -r '.test_name')
        bench_params=$(echo "$params" | jq -r '.parameters')
        bench_args=$(json2args "$bench_params")

        total=$((total + 1))
        if run_single_test "$test_type" "$test_name" "$bench_args"; then
            pass_count=$((pass_count + 1))
        else
            fail_count=$((fail_count + 1))
        fi
    done < <(jq -c --arg model "$model_filter" '.[] | select(.parameters.model == $model)' "$test_file")

    echo "  [$model_filter] ${test_type}: $pass_count passed, $fail_count failed (of $total)"
    return $fail_count
}

# -----------------------------------------------
# Run all tests for a model (latency + throughput)
# Called as a background job in parallel mode
# -----------------------------------------------
run_model_all() {
    local model=$1
    local latency_file=$2
    local throughput_file=$3
    local log_file="$RESULTS_DIR/model_${model//\//_}.log"

    echo ""
    echo "╔════════════════════════════════════════════╗"
    echo "║  MODEL: $model"
    echo "╚════════════════════════════════════════════╝"

    if [[ -f "$latency_file" ]]; then
        local lat_count
        lat_count=$(jq --arg model "$model" '[.[] | select(.parameters.model == $model)] | length' "$latency_file")
        if [[ "$lat_count" -gt 0 ]]; then
            echo ""
            echo "  --- Latency ($lat_count tests) ---"
            run_model_tests "$model" "$latency_file" "latency"
        fi
    fi

    if [[ -f "$throughput_file" ]]; then
        local tp_count
        tp_count=$(jq --arg model "$model" '[.[] | select(.parameters.model == $model)] | length' "$throughput_file")
        if [[ "$tp_count" -gt 0 ]]; then
            echo ""
            echo "  --- Throughput ($tp_count tests) ---"
            run_model_tests "$model" "$throughput_file" "throughput"
        fi
    fi
}

# -----------------------------------------------
# Run benchmark tests sequentially (legacy mode)
# -----------------------------------------------
run_benchmark_tests() {
    local test_type=$1
    local test_file=$2
    local pass_count=0
    local fail_count=0

    if [[ ! -f "$test_file" ]]; then
        echo "  WARNING: Test file not found: $test_file"
        return 1
    fi

    local total
    total=$(jq '. | length' "$test_file")

    echo ""
    echo "╔════════════════════════════════════════════╗"
    echo "║  ${test_type^^} BENCHMARKS ($total tests)"
    echo "╚════════════════════════════════════════════╝"

    while read -r params; do
        test_name=$(echo "$params" | jq -r '.test_name')
        bench_params=$(echo "$params" | jq -r '.parameters')
        bench_args=$(json2args "$bench_params")

        if run_single_test "$test_type" "$test_name" "$bench_args"; then
            pass_count=$((pass_count + 1))
        else
            fail_count=$((fail_count + 1))
        fi
    done < <(jq -c '.[]' "$test_file")

    echo ""
    echo "  ${test_type} result: $pass_count passed, $fail_count failed (of $total)"
}

# -----------------------------------------------
# Main
# -----------------------------------------------
main() {
    echo ""
    echo "=========================================="
    echo "  Spyre vLLM Benchmark Suite"
    echo "  Timestamp: $TIMESTAMP"
    echo "  Parallel:  $PARALLEL"
    echo "=========================================="

    # Check for jq
    if ! command -v jq &>/dev/null; then
        echo "ERROR: jq is required but not found."
        exit 1
    fi

    # Detect which benchmark CLI is available
    detect_bench_command

    # Step 1: Generate test configs from YAML
    echo ""
    echo "=== Generating test configurations ==="
    python3 "$SCRIPT_DIR/generate_test_configs.py" "$CONFIG_FILE" "$RESULTS_DIR"

    local latency_file="$RESULTS_DIR/latency-tests.json"
    local throughput_file="$RESULTS_DIR/throughput-tests.json"

    # Step 2: Run benchmarks
    if [[ "$PARALLEL" == "true" ]]; then
        # Extract unique models from test configs
        local models=()
        if [[ -f "$latency_file" ]]; then
            while IFS= read -r m; do
                models+=("$m")
            done < <(jq -r '.[].parameters.model' "$latency_file" | sort -u)
        fi
        if [[ -f "$throughput_file" ]]; then
            while IFS= read -r m; do
                # Add only if not already in array
                local found=false
                for existing in "${models[@]:-}"; do
                    [[ "$existing" == "$m" ]] && found=true && break
                done
                [[ "$found" == "false" ]] && models+=("$m")
            done < <(jq -r '.[].parameters.model' "$throughput_file" | sort -u)
        fi

        local num_models=${#models[@]}
        echo ""
        echo "=== Parallel mode: $num_models model(s) ==="
        for m in "${models[@]}"; do
            echo "  - $m"
        done

        if [[ $num_models -le 1 ]]; then
            # Single model — no point in parallelism
            echo "  (single model, running sequentially)"
            run_benchmark_tests "latency" "$latency_file"
            run_benchmark_tests "throughput" "$throughput_file"
        else
            # Multiple models — run each in parallel
            echo ""
            echo "=== Launching $num_models parallel model jobs ==="
            local pids=()
            local log_files=()

            for model in "${models[@]}"; do
                local safe_name="${model//\//_}"
                local model_log="$RESULTS_DIR/parallel_${safe_name}.log"
                log_files+=("$model_log")

                echo "  Starting: $model (log: $model_log)"
                run_model_all "$model" "$latency_file" "$throughput_file" > "$model_log" 2>&1 &
                pids+=($!)
            done

            # Wait for all to finish
            echo ""
            echo "=== Waiting for parallel jobs to complete ==="
            local all_passed=true
            for i in "${!pids[@]}"; do
                if wait "${pids[$i]}"; then
                    echo "  DONE: ${models[$i]}"
                else
                    echo "  DONE (with failures): ${models[$i]}"
                    all_passed=false
                fi
            done

            # Print all model logs to stdout (for push script extraction)
            echo ""
            echo "=== Parallel execution logs ==="
            for log_file in "${log_files[@]}"; do
                if [[ -f "$log_file" ]]; then
                    cat "$log_file"
                fi
            done
        fi
    else
        # Sequential mode (legacy)
        run_benchmark_tests "latency" "$latency_file"
        run_benchmark_tests "throughput" "$throughput_file"
    fi

    # Step 3: Collect and summarize results
    echo ""
    echo "=== Collecting results ==="
    python3 "$SCRIPT_DIR/collect_results.py" "$RESULTS_DIR" "$TIMESTAMP" || echo "WARNING: collect_results.py failed (results still available as individual JSONs)"

    # Step 4: Print results to stdout for log capture
    echo ""
    echo "========== BENCHMARK RESULTS (JSON) =========="
    if [[ -f "$RESULTS_DIR/benchmark_summary.json" ]]; then
        cat "$RESULTS_DIR/benchmark_summary.json"
    else
        echo "{\"error\": \"No summary generated\"}"
    fi
    echo ""
    echo "========== END BENCHMARK RESULTS =========="

    # Print individual result JSONs (skip pytorch format — too verbose)
    for f in "$RESULTS_DIR"/*.json; do
        basename_f=$(basename "$f")
        [[ "$basename_f" == *-tests.json ]] && continue
        [[ "$basename_f" == "benchmark_summary.json" ]] && continue
        [[ "$basename_f" == *.pytorch.json ]] && continue
        [[ "$basename_f" == parallel_*.log ]] && continue
        echo ""
        echo "--- $basename_f ---"
        cat "$f"
    done

    # Print pytorch JSONs (needed for model name extraction by push script)
    for f in "$RESULTS_DIR"/*.pytorch.json; do
        [[ -f "$f" ]] || continue
        basename_f=$(basename "$f")
        echo ""
        echo "--- $basename_f ---"
        cat "$f"
    done

    echo ""
    echo "=========================================="
    echo "  Benchmark run complete: $TIMESTAMP"
    echo "=========================================="
}

main "$@"
